"use client";
/* ==========================================================================
   Aura — React bindings.
   GENERATED by tools/aura_react.py from the element registry (js/*.js).
      Do not edit by hand — edit the generator and rerun `just react`.

   Aura ships as framework-free custom elements; this is an OPTIONAL
   ergonomic adapter for React apps. The Aura runtime (dist/aura.js or the
   source modules) must be loaded first so the elements are registered —
   these wrappers do not bundle it.

   Usage:
     import { AuraButton, AuraEditor } from "@aura-design/core/bindings/react";
     <AuraButton variant="primary">Save</AuraButton>
     <AuraEditor name="body" events={{ "aura:change": e => setHtml(e.detail.html) }} />
   ========================================================================== */
import { createElement, forwardRef, useEffect, useImperativeHandle, useLayoutEffect, useRef } from "react";

/* useLayoutEffect warns under SSR; custom elements are client-only anyway. */
const useClientEffect = typeof window === "undefined" ? useEffect : useLayoutEffect;

/* --------------------------------------------------------------------------
 * (#419) Controlled-component bridge
 *
 * Aura form controls mutate their own DOM state on interaction. To support
 * React controlled semantics, the wrapper re-asserts the controlled prop
 * (checked / value) onto the element after every `aura:change` AND on every
 * commit — the standard custom-element controlled shim (cf. @lit/react):
 * an interaction the app does not commit to state snaps straight back.
 *
 * A wrapper is CONTROLLED when the controlled prop is passed together with
 * an `onChange` handler; with either missing the uncontrolled path is
 * untouched (onChange alone is just typed sugar over `aura:change`).
 * ----------------------------------------------------------------------- */

/* tag -> { kind, prop, target, multi, numeric }: which prop controls the
   element, which DOM property the bridge re-asserts it onto, how the
   element decides array-vs-scalar — "always", "never", or the name of the
   attribute that turns multi mode on (#517) — and whether onChange coerces
   the value to a number (#518, a scalar numeric control like aura-stepper).
   Generated — 10 controls. */
const CONTROLLED = {
  "aura-checkbox":     { kind: "checked", prop: "checked", target: "checked", multi: "never", numeric: false },
  "aura-color-picker": { kind: "value", prop: "value", target: "value", multi: "never", numeric: false },
  "aura-datepicker":   { kind: "value", prop: "value", target: "value", multi: "never", numeric: false },
  "aura-radio":        { kind: "checked", prop: "checked", target: "checked", multi: "never", numeric: false },
  "aura-range":        { kind: "value", prop: "value", target: "value", multi: "range", numeric: false },
  "aura-select":       { kind: "value", prop: "value", target: "value", multi: "multiple", numeric: false },
  "aura-stepper":      { kind: "value", prop: "value", target: "value", multi: "never", numeric: true },
  "aura-switch":       { kind: "checked", prop: "checked", target: "checked", multi: "never", numeric: false },
  "aura-tag-input":    { kind: "tags", prop: "value", target: "tags", multi: "always", numeric: false },
  "aura-timepicker":   { kind: "value", prop: "value", target: "value", multi: "never", numeric: false },
};

/* Resolve whether a controlled element is in MULTI (array) mode RIGHT NOW
   from the element's actual mode — never by sniffing for a comma (#517).
   "always"/"never" are fixed; any other ctl.multi is the name of the
   boolean-ish attribute that turns multi on (aura-select `multiple`,
   aura-range `range`), read straight off the live element. A single-value
   control whose value legitimately contains a comma (aura-select
   value="Paris, France") therefore stays scalar and never gets split. */
function isMultiMode(el, ctl) {
  if (ctl.multi === "always") return true;
  if (ctl.multi === "never") return false;
  return !!(el && el.hasAttribute && el.hasAttribute(ctl.multi));
}

/* Canonicalize a multi-value control's value into a trimmed array,
   regardless of whether it arrives as a comma string (the form every
   element serializes: aura-range dual `get value()`, aura-select-multiple
   setter, aura-tag-input prop sugar) or an already-split array (the form
   aura-select-multiple `get value()` and aura-tag-input `get tags()`
   read back). Both sides MUST normalize identically or controlledKey
   never matches and the bridge re-asserts forever (#467/#475). Empty
   entries are dropped only for `tags` (commas are separators); `value`
   keeps positional entries so a dual range never collapses a slot. */
function normalizeMulti(kind, v) {
  const parts = Array.isArray(v) ? v : String(v).split(",");
  const trimmed = parts.map((s) => String(s).trim());
  return kind === "tags" ? trimmed.filter((s) => s !== "") : trimmed;
}

/* Normalize a controlled value into a comparable string key. `multi` is
   the element's resolved array-mode (from isMultiMode) — the SAME value
   is used for both the element read-back and the prop, so the comma-string
   and array shapes of one value compare equal (#467/#475) while a scalar
   control's comma-bearing single value is preserved whole (#517). */
function controlledKey(kind, v, multi) {
  if (v === undefined || v === null) return "";
  if (kind === "checked") return v ? "1" : "";
  if (kind === "tags" || multi || Array.isArray(v)) {
    return normalizeMulti(kind, v).join("\u0000");
  }
  return String(v);
}

/* Comma-separated string -> trimmed non-empty list (tag-input prop sugar). */
function splitTags(v) {
  return normalizeMulti("tags", v);
}

/* Read the element's CURRENT state for a controlled config. */
function readControlled(el, ctl) {
  if (ctl.kind === "checked") return !!el[ctl.target];
  if (ctl.kind === "tags") return el[ctl.target] || [];
  const v = el[ctl.target];
  return v === undefined || v === null ? el.getAttribute(ctl.prop) : v;
}

/* Write a controlled value onto the element, suppressing the bridge's own
   listener for any event the element dispatches during the write. */
function writeControlled(el, ctl, v) {
  el.__auraControlledLock = true;
  try {
    if (ctl.kind === "checked") el[ctl.target] = !!v;
    else if (ctl.kind === "tags") el[ctl.target] = splitTags(v);
    else el[ctl.target] = v;
  } finally {
    el.__auraControlledLock = false;
  }
}

/* (#666) Serialize a controlled value into its INITIAL server-render
   attribute form, so a controlled control renders its checked/value from
   the first paint under renderToString — closing the SSR gap the
   uncontrolled path already covers (#473). Returns either the empty-string
   present-attribute, an absent marker (undefined), or the string value.
   The client effects (assertControlled) still own post-hydration
   reconciliation; this is purely the first-paint attribute. */
const CONTROLLED_ABSENT = undefined;
function controlledInitialAttr(ctl, multi, v) {
  if (v === undefined || v === null) return CONTROLLED_ABSENT;
  if (ctl.kind === "checked") return v ? "" : CONTROLLED_ABSENT;
  if (ctl.kind === "tags" || multi || Array.isArray(v)) {
    return normalizeMulti(ctl.kind, v).join(",");
  }
  return String(v);
}

/* Re-assert `value` unless the element already reflects it. The array-mode
   is resolved ONCE from the live element and used for both keys, so the
   comparison is mode-consistent (#517). */
function assertControlled(el, ctl, value) {
  if (value === undefined) return;
  const multi = isMultiMode(el, ctl);
  if (controlledKey(ctl.kind, readControlled(el, ctl), multi) === controlledKey(ctl.kind, value, multi)) return;
  writeControlled(el, ctl, value);
}

/* Coerce a stepper's change value to a number: the element is conceptually
   numeric (#518), so onChange hands the app a number — matching the typed
   `onChange?: (value: number, …)` — instead of the raw input string. An
   unparseable value passes through untouched. */
function coerceChangeValue(ctl, v) {
  if (ctl.numeric && typeof v === "string" && v.trim() !== "") {
    const n = Number(v);
    return Number.isNaN(n) ? v : n;
  }
  return v;
}

/* The value handed to onChange: prefer the event detail, fall back to the
   element's current state (native `change` events carry no detail). */
function readChangeValue(el, ctl, event) {
  const d = event && event.detail;
  if (ctl.kind === "checked") {
    return d && typeof d.checked === "boolean" ? d.checked : !!readControlled(el, ctl);
  }
  if (ctl.kind === "tags") return d && d.tags ? d.tags : readControlled(el, ctl);
  const raw = d && d.value !== undefined ? d.value : readControlled(el, ctl);
  return coerceChangeValue(ctl, raw);
}

/* Wrap one custom-element tag as a React component. */
export function createAuraComponent(tagName) {
  const ctl = CONTROLLED[tagName] || null;
  const Component = forwardRef(function AuraComponent({ children, events, ...props }, ref) {
    const innerRef = useRef(null);
    useImperativeHandle(ref, () => innerRef.current, []);

    /* (#419) The bridge intercepts onChange only for controllable form
       controls; for every other tag the prop passes through untouched. */
    let onChange;
    if (ctl && typeof props.onChange === "function") {
      onChange = props.onChange;
      delete props.onChange;
    }
    const controlled = !!(ctl && onChange && props[ctl.prop] !== undefined);
    const bridgeRef = useRef({ controlled: false, value: undefined, onChange: undefined });
    const controlledValue = ctl ? props[ctl.prop] : undefined;
    useClientEffect(() => {
      bridgeRef.current = { controlled, value: controlledValue, onChange };
    });
    /* (#666) For a controlled control, remove the raw prop from the spread
       (its shape may be an array or boolean React would mis-serialize) but
       capture the INITIAL value as a server-render attribute so
       renderToString — and the first client paint — carry the controlled
       checked/value, instead of rendering blank and only snapping in a
       client effect (the old `delete`-only path lost the #473 guarantee at
       the controlled API). The imperative effects below still own all
       post-hydration reconciliation, so React does not fight the live DOM.
       Multi-mode is read from the mode attribute PRESENT IN PROPS (no live
       element exists at render), falling back to an array-shaped value. */
    let controlledInitial = CONTROLLED_ABSENT;
    if (controlled) {
      const renderMulti = ctl.multi === "always" ||
        (ctl.multi !== "never" && (props[ctl.multi] !== undefined && props[ctl.multi] !== false));
      controlledInitial = controlledInitialAttr(ctl, renderMulti, controlledValue);
      delete props[ctl.prop];
    }

    /* Re-assert the controlled prop after EVERY commit: React's renderer
       only diffs against its own previous output, so element-initiated DOM
       changes (a user toggle the app rejected, an internal value write)
       would otherwise stick. (#666) On the FIRST client commit the bridge
       force-writes the value onto the element PROPERTY, so the live
       property — not just the server-rendered attribute the new SSR path
       emits — is authoritative after hydration (the element may not have
       initialized its property from the attribute yet). Subsequent commits
       use the cheap assertControlled compare-then-write. */
    const mountedRef = useRef(false);
    useClientEffect(() => {
      const el = innerRef.current;
      if (!el || !controlled) return;
      if (!mountedRef.current) {
        mountedRef.current = true;
        if (controlledValue !== undefined) writeControlled(el, ctl, controlledValue);
        return;
      }
      assertControlled(el, ctl, controlledValue);
    });

    /* One stable listener for the element's change signal: onChange sugar
       plus the synchronous snap-back while uncommitted. Attached only
       while an onChange handler exists (controlled implies onChange), so
       plain usage pays nothing. The handler is read through bridgeRef, so
       inline-handler identity churn never re-wires the listener. */
    const hasBridge = !!(ctl && onChange);
    useEffect(() => {
      const el = innerRef.current;
      if (!el || !hasBridge) return undefined;
      const listener = (event) => {
        if (el.__auraControlledLock) return; // our own re-assert write
        const state = bridgeRef.current;
        if (state.onChange) state.onChange(readChangeValue(el, ctl, event), event);
        if (state.controlled) assertControlled(el, ctl, state.value);
      };
      el.addEventListener("aura:change", listener);
      return () => el.removeEventListener("aura:change", listener);
    }, [hasBridge]);

    /* (#417/#473) Boolean handling. A `false` boolean must NEVER reach the
       createElement spread: React ≤18 serializes checked={false} into the
       PRESENT attribute checked="false", which hasAttribute() reads as ON.
       But a `true` boolean DOES go into the spread as the empty-string
       attribute (disabled: ""): that serializes identically on every React
       version and on the server, so an initially-disabled/checked control
       renders correct from the first paint and under renderToString (#473) —
       no one-frame flash. The effect below still owns the false/dropped case
       (attribute removal), which the spread cannot express. */
    /* (#472) The wrappers advertise a `class` alias, but React reserves
       `className`. The fix is to spread a RAW `class` key (not
       `className`): on a custom element React serializes a `class` prop
       to a real `class="…"` attribute identically under renderToString
       AND on the client for every supported React (>=17), whereas a
       `className` prop emits the junk literal `className="…"` attribute
       under SSR on React 17/18 (only React 19 maps it to `class`). React's
       own reconciler also owns the change/removal cases, so no imperative
       effect is needed. An explicit `className` wins over the `class`
       alias. */
    const classValue = props.className !== undefined ? props.className : props.class;
    const attrProps = {};
    const boolProps = {};
    for (const key of Object.keys(props)) {
      const value = props[key];
      if (key === "class" || key === "className") continue; // handled above
      if (typeof value === "boolean") {
        boolProps[key] = value;
        /* (#473) Render `true` as the empty-string attribute so it is
           present from the first paint and in SSR markup; `false` is
           dropped here and the effect removes any stale attribute. */
        if (value) attrProps[key] = "";
      } else if (value !== undefined) attrProps[key] = value;
    }
    if (classValue !== undefined && classValue !== null) attrProps.class = classValue;
    /* (#666) Inject the controlled control's INITIAL value as a SERVER-
       render attribute (checked="" / value="…"), so renderToString carries
       the controlled state from the first paint instead of rendering blank.
       SERVER-ONLY (typeof window === "undefined"): putting it in the client
       vdom would set the attribute at element-CREATION time, firing the
       element's attributeChangedCallback against an unbuilt internal DOM
       (a crash). On the client the mount effect below force-writes the value
       onto the element PROPERTY AFTER connect, which is the safe, correct
       owner of the first client value. It is never a boolProp, so on the
       server it is a plain present-attribute on every React version. */
    if (typeof window === "undefined" && controlledInitial !== CONTROLLED_ABSENT) {
      attrProps[ctl.prop] = controlledInitial;
    }
    const boolJSON = JSON.stringify(boolProps);
    useClientEffect(() => {
      const el = innerRef.current;
      if (!el) return;
      const bools = JSON.parse(boolJSON);
      for (const key of Object.keys(bools)) {
        if (bools[key]) el.setAttribute(key, "");
        else el.removeAttribute(key);
      }
      /* Clear booleans that were set on a previous render but dropped since. */
      for (const key of el.__auraBooleanKeys || []) {
        if (!(key in bools)) el.removeAttribute(key);
      }
      el.__auraBooleanKeys = Object.keys(bools);
    }, [boolJSON]);

    /* (#417) Stable listeners: handlers live in a ref so inline `events`
       object identity changing per render never tears listeners down;
       attach/detach only when the SET of event names changes. */
    const eventsRef = useRef(events);
    useClientEffect(() => { eventsRef.current = events; });
    const eventKey = events ? Object.keys(events).sort().join("\n") : "";
    useEffect(() => {
      const el = innerRef.current;
      if (!el || !eventKey) return undefined;
      const pairs = eventKey.split("\n").map((name) => {
        const listener = (event) => {
          const handlers = eventsRef.current;
          const handler = handlers && handlers[name];
          if (handler) handler(event);
        };
        el.addEventListener(name, listener);
        return [name, listener];
      });
      return () => {
        for (const [name, listener] of pairs) el.removeEventListener(name, listener);
      };
    }, [eventKey]);

    return createElement(tagName, { ref: innerRef, ...attrProps }, children);
  });
  Component.displayName = "Aura(" + tagName + ")";
  return Component;
}

